import { getAQIStatus } from "../lib/utils";

export default function AirQualityCard({ aqi, city }: { aqi: number, city: string }) {
  const status = getAQIStatus(aqi);

  return (
    <div className={`p-6 rounded-2xl shadow-lg ${status.color} ${status.text}`}>
      <h3 className="text-xl font-bold">{city}</h3>
      <p className="text-sm opacity-80">Current Air Quality Index</p>
      <div className="text-6xl font-black my-4">{aqi}</div>
      <p className="font-semibold uppercase tracking-wider">{status.label}</p>
    </div>
  );
}