'use client';
import AirQualityCard from '../../components/AirQualityCard';
import PollutantChart from '../../components/PollutantChart';
import AICounsel from '../../components/AICounsel';
import { supabase } from '../../lib/supabase';

import { useEffect, useState } from 'react';
export default function Dashboard() {
  const [data, setData] = useState<any>(null);
  const [insight, setInsight] = useState("");

  useEffect(() => {
    async function fetchData() {
      // 1. Fetch Real-time Data
      const res = await fetch('/api/environment');
      const json = await res.json();
      const current = json.data.current.pollution;
      setData(json.data);

      // 2. Get AI Insights
      const aiRes = await fetch('/api/ai-coach', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ aqi: current.aqius, city: json.data.city })
      });
      if (aiRes.ok) {
        const aiJson = await aiRes.json();
        setInsight(aiJson.insight);
      } else {
        setInsight("AI is currently offline.");
      }

      // 3. Save to Database (Real-life problem: Historical Tracking)
      if (supabase) {
        await supabase.from('env_logs').insert([
          { city: json.data.city, aqi: current.aqius, timestamp: new Date() }
        ]);
      }
    }
    fetchData();
  }, []);

  if (!data) return <div className="p-10 text-center">Loading Environment Stats...</div>;

  return (
    <main className="max-w-6xl mx-auto p-6 space-y-6">
      <h1 className="text-3xl font-bold text-gray-800">Environmental Insights</h1>
      
      <div className="grid md:grid-cols-2 gap-6">
        <AirQualityCard aqi={data.current.pollution.aqius} city={data.city} />
        <AICounsel insight={insight} />
      </div>

      <div className="bg-white p-6 rounded-2xl shadow-md">
        <h3 className="font-bold mb-4">Pollutant Breakdown</h3>
        <PollutantChart data={data.current.pollution} />
      </div>
    </main>
  );
}